import { Injectable, NotFoundException } from '@nestjs/common';
import { PrismaService } from '../database/prisma.service';
import { CreateListenerDto, UpdateListenerDto } from './dto/listener.dto';
import { ListenerStatus } from '@prisma/client';

@Injectable()
export class ListenerService {
  constructor(private readonly prisma: PrismaService) {}

  async create(dto: CreateListenerDto) {
    return this.prisma.listener.create({
      data: {
        name: dto.name,
        type: dto.type,
        host: dto.host || '0.0.0.0',
        port: dto.port,
        protocol: dto.protocol || 'TCP',
        status: ListenerStatus.INACTIVE,
        bindIp: dto.bindIp || 'All Interfaces',
        payload: dto.payload,
        encoding: dto.encoding,
      },
    });
  }

  async findAll() {
    return this.prisma.listener.findMany({
      include: {
        connections: {
          orderBy: { lastSeen: 'desc' },
          take: 5,
        },
        _count: {
          select: { connections: true },
        },
      },
      orderBy: { createdAt: 'desc' },
    });
  }

  async findOne(id: string) {
    const listener = await this.prisma.listener.findUnique({
      where: { id },
      include: {
        connections: {
          orderBy: { lastSeen: 'desc' },
        },
      },
    });
    if (!listener) {
      throw new NotFoundException('Listener configuration not found');
    }
    return listener;
  }

  async update(id: string, dto: UpdateListenerDto) {
    return this.prisma.listener.update({
      where: { id },
      data: dto,
    });
  }

  async delete(id: string) {
    return this.prisma.listener.delete({ where: { id } });
  }

  async start(id: string) {
    const listener = await this.prisma.listener.update({
      where: { id },
      data: { status: ListenerStatus.ACTIVE },
    });

    // TODO: Actually start the listener service (integrate with Go scanner or separate listener service)
    console.log(`[+] Listener ${listener.name} started on ${listener.host}:${listener.port}`);

    return listener;
  }

  async stop(id: string) {
    const listener = await this.prisma.listener.update({
      where: { id },
      data: { status: ListenerStatus.INACTIVE },
    });

    // TODO: Actually stop the listener service
    console.log(`[-] Listener ${listener.name} stopped`);

    return listener;
  }

  async getConnections(listenerId: string) {
    return this.prisma.connection.findMany({
      where: { listenerId },
      orderBy: { lastSeen: 'desc' },
    });
  }

  async getStats() {
    const total = await this.prisma.listener.count();

    const byStatus = await this.prisma.listener.groupBy({
      by: ['status'],
      _count: true,
    });

    const statusMap = byStatus.reduce((acc, item) => {
      acc[item.status] = item._count;
      return acc;
    }, {} as Record<string, number>);

    const totalConnections = await this.prisma.connection.count();
    const activeConnections = await this.prisma.connection.count({
      where: {
        lastSeen: {
          gte: new Date(Date.now() - 5 * 60 * 1000), // Active in last 5 minutes
        },
      },
    });

    return {
      totalListeners: total,
      activeListeners: statusMap['ACTIVE'] || 0,
      inactiveListeners: statusMap['INACTIVE'] || 0,
      errorListeners: statusMap['ERROR'] || 0,
      totalConnections,
      activeConnections,
    };
  }
}

