import { io, Socket } from 'socket.io-client';

const WS_URL = process.env.NEXT_PUBLIC_API_URL?.replace('/api', '') || 'http://localhost:8000';

class WebSocketClient {
  private socket: Socket | null = null;

  connect() {
    if (this.socket?.connected) return this.socket;

    this.socket = io(WS_URL, {
      transports: ['websocket'],
      autoConnect: true,
    });

    this.socket.on('connect', () => {
      console.log('[+] WebSocket connected to VulnX Stream');
    });

    this.socket.on('disconnect', () => {
      console.log('[-] WebSocket disconnected from VulnX Stream');
    });

    return this.socket;
  }

  disconnect() {
    if (this.socket) {
      this.socket.disconnect();
      this.socket = null;
    }
  }

  joinScanLogs(scanId: string) {
    if (!this.socket) this.connect();
    this.socket?.emit('joinScanLogs', { scanId });
  }

  onLogStream(callback: (data: { scanId: string; message: string; timestamp: Date }) => void) {
    if (!this.socket) this.connect();
    this.socket?.on('logStream', callback);
  }

  onScanStatusUpdate(callback: (data: { scanId: string; status: string; timestamp: Date }) => void) {
    if (!this.socket) this.connect();
    this.socket?.on('scanStatusUpdate', callback);
  }

  off(event: string) {
    this.socket?.off(event);
  }
}

