import { useEffect, useState } from 'react';
import { apiClient } from '@/lib/api-client';
import { wsClient } from '@/lib/websocket-client';

export function useDashboardData() {
  const [targets, setTargets] = useState([]);
  const [vulnerabilities, setVulnerabilities] = useState([]);
  const [vulnStats, setVulnStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchDashboardData();
    setupWebSocket();

    return () => {
      wsClient.off('scanStatusUpdate');
      wsClient.off('logStream');
    };
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);

      // Fetch all data in parallel
      const [targetsData, vulnStatsData, vulnerabilitiesData] = await Promise.all([
        apiClient.getTargets(),
        apiClient.getVulnerabilityStats(),
        apiClient.getVulnerabilities(),
      ]);

      setTargets(targetsData);
      setVulnStats(vulnStatsData);
      setVulnerabilities(vulnerabilitiesData);
      setError(null);
    } catch (err: any) {
      console.error('Failed to fetch dashboard data:', err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const setupWebSocket = () => {
    wsClient.connect();

    // Listen for scan status updates
    wsClient.onScanStatusUpdate((data) => {
      console.log('Scan status update:', data);
      // Refresh targets when scan completes
      if (data.status === 'COMPLETED') {
        fetchDashboardData();
      }
    });

    // Listen for real-time logs
    wsClient.onLogStream((data) => {
      console.log('Scan log:', data.message);
      // You can update UI with real-time logs here
    });
  };

  const triggerScan = async (targetId: string) => {
    try {
      const scan = await apiClient.triggerScan(targetId);
      console.log('Scan triggered:', scan);

      // Join the scan logs room for real-time updates
      wsClient.joinScanLogs(scan.id);

      // Refresh data
      await fetchDashboardData();

      return scan;
    } catch (err: any) {
      console.error('Failed to trigger scan:', err);
      throw err;
    }
  };

  return {
    targets,
    vulnerabilities,
    vulnStats,
    loading,
    error,
    triggerScan,
    refresh: fetchDashboardData,
  };
}

