'use client';

import React, { useState, useEffect, useRef } from 'react';
import { 
  Shield, Terminal as TermIcon, ShieldAlert, Cpu, 
  Layers, Users, Zap, Globe, Search, Play, ArrowRight,
  Sparkles, CheckCircle2, ChevronRight, RefreshCcw, Wifi, AlertTriangle,
  Brain, Network, Code, Lock, Compass, FileText, Database, TrendingUp,
  Heart, Github, Slack, MessageSquare, Check, Plus, Menu, X, ChevronDown,
  Settings, Key, Compass as CompassIcon, BookMarked, Activity, Bell, Send,
  ChevronUp, ZoomIn, ZoomOut, Maximize2, SearchCode, FileSpreadsheet
} from 'lucide-react';
import Link from 'next/link';
import { apiClient } from '@/lib/api-client';
import { wsClient } from '@/lib/websocket-client';
import { useRouter } from 'next/navigation';

export default function Dashboard() {
  const router = useRouter();

  // Auth check
  useEffect(() => {
    const token = localStorage.getItem('vulnx_token');
    if (!token) {
      router.push('/login');
    }
  }, [router]);

  // Navigation active tab
  const [activeNav, setActiveNav] = useState('dashboard');

  // Search command palette state
  const [isSearchFocused, setIsSearchFocused] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // Real data from API
  const [targets, setTargets] = useState<any[]>([]);
  const [vulnerabilities, setVulnerabilities] = useState<any[]>([]);
  const [vulnStats, setVulnStats] = useState<any>(null);
  const [scans, setScans] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Shell Terminal State
  const [shellLogs, setShellLogs] = useState<string[]>([
    '[+] VulnX Hunter Terminal Ready',
    '[+] Type "help" for available commands',
  ]);
  const [shellInput, setShellInput] = useState('');

  // AI assistant chat state
  const [aiInput, setAiInput] = useState('');
  const [aiChats, setAiChats] = useState<Array<{ role: 'user' | 'assistant'; text: string; time: string }>>([
    {
      role: 'assistant',
      text: 'Hello! I\'m your AI security assistant. Ask me about vulnerabilities, threats, or security best practices.',
      time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    }
  ]);

  const terminalEndRef = useRef<HTMLDivElement>(null);

  // Fetch all data on mount
  useEffect(() => {
    fetchDashboardData();
    setupWebSocket();

    return () => {
      wsClient.off('scanStatusUpdate');
      wsClient.off('logStream');
    };
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      setError('');

      const [targetsData, vulnStatsData, vulnerabilitiesData] = await Promise.all([
        apiClient.getTargets(),
        apiClient.getVulnerabilityStats(),
        apiClient.getVulnerabilities(),
      ]);

      setTargets(targetsData);
      setVulnStats(vulnStatsData);
      setVulnerabilities(vulnerabilitiesData);

      // Fetch scans for each target
      const scansPromises = targetsData.slice(0, 5).map((t: any) => 
        apiClient.getScansByTarget(t.id).catch(() => [])
      );
      const scansData = await Promise.all(scansPromises);
      setScans(scansData.flat().slice(0, 5));

    } catch (err: any) {
      console.error('Failed to fetch dashboard data:', err);
      setError(err.message || 'Failed to load dashboard data');
    } finally {
