'use client';

import React, { useState, useEffect } from 'react';
import { 
  Shield, Layers, Users, Zap, Globe, Search, Plus,
  Sparkles, ChevronDown, RefreshCcw, AlertTriangle,
  Network, FileText, Activity, BookMarked,
  Settings, Key, Compass as CompassIcon, Bell, 
  MessageSquare, Edit, Trash2, Play
} from 'lucide-react';
import Link from 'next/link';
import { apiClient } from '@/lib/api-client';
import { wsClient } from '@/lib/websocket-client';
import { useRouter } from 'next/navigation';

export default function TargetsPage() {
  const router = useRouter();

  // Auth check
  useEffect(() => {
    const token = localStorage.getItem('vulnx_token');
    if (!token) {
      router.push('/login');
    }
  }, [router]);

  // State
  const [targets, setTargets] = useState<any[]>([]);
  const [selectedTarget, setSelectedTarget] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [activeTab, setActiveTab] = useState<'overview' | 'scans' | 'vulns'>('overview');

  // Fetch targets on mount
  useEffect(() => {
    fetchTargets();
    setupWebSocket();

    return () => {
      wsClient.off('scanStatusUpdate');
    };
  }, []);

  const fetchTargets = async () => {
    try {
      setLoading(true);
      setError('');
      const data = await apiClient.getTargets();
      setTargets(data);

      // Select first target by default
      if (data.length > 0 && !selectedTarget) {
        setSelectedTarget(data[0]);
      }
    } catch (err: any) {
      console.error('Failed to fetch targets:', err);
      setError(err.message || 'Failed to load targets');
    } finally {
      setLoading(false);
    }
  };

  const setupWebSocket = () => {
    wsClient.connect();
    wsClient.onScanStatusUpdate((data) => {
      if (data.status === 'COMPLETED') {
        fetchTargets();
      }
    });
  };

  // Create new target
  const handleCreateTarget = () => {
    const name = prompt('Enter target name:');
    if (!name) return;

    const scope = prompt('Enter target scope (domain/IP):');
    if (!scope) return;

    const priority = prompt('Enter priority (LOW/MEDIUM/HIGH/CRITICAL):', 'MEDIUM');
    if (!priority) return;

    createTarget(name, scope, priority);
  };

  const createTarget = async (name: string, scope: string, priority: string) => {
    try {
      const newTarget = await apiClient.createTarget({
        name,
        type: 'DOMAIN',
        scope,
        priority: priority.toUpperCase(),
        tags: ['manual-created']
      });

      setTargets(prev => [newTarget, ...prev]);
      setSelectedTarget(newTarget);
      alert(`Target "${name}" created successfully!`);
    } catch (err: any) {
      alert('Failed to create target: ' + err.message);
    }
  };

  // Delete target
  const handleDeleteTarget = async (targetId: string) => {
    if (!confirm('Are you sure you want to delete this target?')) return;

    try {
      await apiClient.deleteTarget(targetId);
      setTargets(prev => prev.filter(t => t.id !== targetId));

      if (selectedTarget?.id === targetId) {
        setSelectedTarget(targets[0] || null);
      }

      alert('Target deleted successfully!');
    } catch (err: any) {
      alert('Failed to delete target: ' + err.message);
    }
  };

  // Trigger scan
  const handleTriggerScan = async (targetId: string) => {
    try {
      const scan = await apiClient.triggerScan(targetId);
      wsClient.joinScanLogs(scan.id);
      alert(`Scan started! Scan ID: ${scan.id}\nWatch the dashboard for real-time updates.`);
      await fetchTargets();
    } catch (err: any) {
      alert('Failed to start scan: ' + err.message);
    }
  };

  // Filter targets by search
  const filteredTargets = targets.filter(t => 
    t.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    t.scope.toLowerCase().includes(searchQuery.toLowerCase())
  );

  // Loading state
  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-[#050812]">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-cyber-green border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-cyber-green font-mono text-sm uppercase tracking-wider">
            Loading Targets...
          </p>
        </div>
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-[#050812] p-6">
        <div className="bg-[#0b1120] border border-cyber-pink/20 rounded-sm p-6 max-w-md">
          <div className="flex items-center gap-3 mb-4">
            <div className="w-12 h-12 rounded-full bg-cyber-pink/10 flex items-center justify-center">
              <span className="text-2xl">⚠️</span>
            </div>
            <div>
              <h3 className="text-white font-heading font-bold text-lg">Error</h3>
              <p className="text-cyber-muted text-xs font-mono">Failed to load targets</p>
            </div>
          </div>
          <p className="text-white font-mono text-sm mb-4">{error}</p>
          <button 
            onClick={fetchTargets}
            className="w-full bg-cyber-green text-black font-heading font-bold text-xs uppercase py-2 rounded-sm hover:bg-cyber-green/90 transition-colors"
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#050812] text-cyber-text font-sans overflow-hidden select-none scanline">

      {/* LEFT SIDEBAR */}
      <aside className="w-64 bg-[#080b14] border-r border-white/5 flex flex-col justify-between shrink-0 h-full overflow-y-auto">
        <div className="space-y-6 pt-6">
          <div className="px-6 flex items-center gap-3">
            <div className="p-2 bg-gradient-to-br from-cyber-green to-cyber-blue border border-black shadow-[2px_2px_0px_0px_rgba(0,0,0,1)] rounded-sm">
              <Shield className="w-5 h-5 text-black" />
            </div>
            <div>
              <span className="font-heading font-extrabold text-base tracking-tight text-white block">
                VULNX <span className="text-cyber-green">HUNTER</span>
              </span>
              <span className="text-[8px] font-mono text-cyber-blue tracking-widest block uppercase font-bold">
                Workspaces Center
              </span>
            </div>
          </div>

          <nav className="space-y-5 px-3">
            <div className="space-y-1">
              <Link 
                href="/dashboard"
                className="w-full flex items-center gap-2.5 px-3 py-2 rounded-sm text-xs font-heading font-bold uppercase text-cyber-muted hover:text-white hover:bg-white/[0.02] transition-colors"
              >
                <Layers className="w-4 h-4" />
                <span>Dashboard</span>
              </Link>
            </div>

            <div className="space-y-1">
              <span className="px-3 text-[9px] font-mono text-white/30 uppercase tracking-widest font-bold block mb-2">
                RECON & SCAN
              </span>
              {[
                { id: 'targets', label: 'Targets', icon: Globe, path: '/targets' },
                { id: 'listeners', label: 'Listeners', icon: Zap, path: '/listeners' },
                { id: 'ai-assistant', label: 'AI Assistant', icon: Sparkles, path: '/ai-assistant' },
              ].map(item => {
                const Icon = item.icon;
                const isActive = item.id === 'targets';
                return (
                  <Link
                    key={item.id}
                    href={item.path}
                    className={`w-full flex items-center gap-2.5 px-3 py-2 rounded-sm text-xs font-heading font-bold uppercase transition-all ${
                      isActive
                        ? 'bg-cyber-green/10 text-cyber-green border border-cyber-green/20'
                        : 'text-cyber-muted hover:text-white hover:bg-white/[0.02]'
                    }`}
                  >
                    <Icon className="w-4 h-4" />
                    <span>{item.label}</span>
                  </Link>
                );
              })}
            </div>
          </nav>
        </div>

        <div className="p-4 border-t border-white/5">
          <button
            onClick={() => {
              apiClient.logout();
              router.push('/login');
            }}
            className="w-full px-3 py-2 bg-cyber-pink/10 border border-cyber-pink/20 text-cyber-pink font-mono text-xs font-bold uppercase rounded-sm hover:bg-cyber-pink/20 transition-colors"
          >
            Logout
          </button>
        </div>
      </aside>

      {/* MAIN CONTENT */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">

        {/* Header */}
        <header className="h-16 border-b border-white/5 px-6 flex justify-between items-center bg-[#080b14]/50 backdrop-blur-md shrink-0">
          <div className="relative w-80">
            <Search className="absolute left-3 top-2.5 w-4 h-4 text-cyber-muted" />
            <input 
              type="text" 
              placeholder="Search targets..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-[#050812] border border-white/10 focus:border-cyber-green outline-none py-1.5 pl-9 pr-4 text-xs font-mono text-white rounded-sm placeholder-cyber-muted/60 transition-all"
            />
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={fetchTargets}
              className="p-2 border border-white/5 hover:border-cyber-green bg-[#080b14] text-cyber-muted hover:text-white rounded-sm transition-all"
              title="Refresh"
            >
              <RefreshCcw className="w-4.5 h-4.5" />
            </button>

            <button
              onClick={handleCreateTarget}
              className="flex items-center gap-2 px-4 py-2 bg-cyber-green text-black font-heading font-bold text-xs uppercase rounded-sm hover:bg-cyber-green/90 transition-colors"
            >
              <Plus className="w-4 h-4" />
              New Target
            </button>
          </div>
        </header>

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto p-6">

          {/* Title */}
          <div className="mb-6">
            <h1 className="font-heading font-bold text-2xl text-white tracking-tight mb-2">
              Targets Management
            </h1>
            <p className="text-xs font-mono text-cyber-muted">
              {filteredTargets.length} targets found
            </p>
          </div>

          {/* Targets Grid */}
          {filteredTargets.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20">
              <Globe className="w-16 h-16 text-cyber-muted mb-4" />
              <h3 className="text-white font-heading font-bold text-lg mb-2">No Targets Found</h3>
              <p className="text-cyber-muted font-mono text-sm mb-4">
                {searchQuery ? 'No targets match your search' : 'Create your first target to get started'}
              </p>
              {!searchQuery && (
                <button
                  onClick={handleCreateTarget}
                  className="flex items-center gap-2 px-4 py-2 bg-cyber-green text-black font-heading font-bold text-xs uppercase rounded-sm hover:bg-cyber-green/90 transition-colors"
                >
                  <Plus className="w-4 h-4" />
                  Create Target
                </button>
              )}
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {filteredTargets.map((target) => (
                <div 
                  key={target.id}
                  className="bg-[#0b1120] border border-white/5 rounded-sm p-4 hover:border-cyber-green/20 transition-all"
                >
                  {/* Target Header */}
                  <div className="flex justify-between items-start mb-3">
                    <div className="flex-1">
                      <h3 className="text-white font-heading font-bold text-sm mb-1">
                        {target.name}
                      </h3>
                      <p className="text-cyber-muted font-mono text-xs truncate">
                        {target.scope}
                      </p>
                    </div>
                    <span className={`text-[8px] font-mono font-bold px-2 py-1 rounded-sm ${
                      target.priority === 'CRITICAL' ? 'bg-cyber-pink/10 text-cyber-pink border border-cyber-pink/20' :
                      target.priority === 'HIGH' ? 'bg-[#FF8A00]/10 text-[#FF8A00] border border-[#FF8A00]/20' :
                      target.priority === 'MEDIUM' ? 'bg-[#FFD600]/10 text-[#FFD600] border border-[#FFD600]/20' :
                      'bg-cyber-blue/10 text-cyber-blue border border-cyber-blue/20'
                    }`}>
                      {target.priority}
                    </span>
                  </div>

                  {/* Stats */}
                  <div className="grid grid-cols-3 gap-2 mb-3">
                    <div className="bg-[#050812] border border-white/5 rounded-sm p-2 text-center">
                      <p className="text-[10px] font-mono text-cyber-muted uppercase">Scans</p>
                      <p className="text-sm font-heading font-bold text-white">{target.scans?.length || 0}</p>
                    </div>
                    <div className="bg-[#050812] border border-white/5 rounded-sm p-2 text-center">
                      <p className="text-[10px] font-mono text-cyber-muted uppercase">Vulns</p>
                      <p className="text-sm font-heading font-bold text-cyber-pink">{target.vulnerabilities?.length || 0}</p>
                    </div>
                    <div className="bg-[#050812] border border-white/5 rounded-sm p-2 text-center">
                      <p className="text-[10px] font-mono text-cyber-muted uppercase">Type</p>
                      <p className="text-[10px] font-mono font-bold text-cyber-green">{target.type}</p>
                    </div>
                  </div>

                  {/* Tags */}
                  {target.tags && target.tags.length > 0 && (
                    <div className="flex flex-wrap gap-1 mb-3">
                      {target.tags.slice(0, 3).map((tag: string, idx: number) => (
                        <span key={idx} className="text-[8px] font-mono bg-cyber-blue/10 text-cyber-blue border border-cyber-blue/20 px-1.5 py-0.5 rounded-sm">
                          {tag}
                        </span>
                      ))}
                    </div>
                  )}

                  {/* Actions */}
                  <div className="flex gap-2">
                    <button
                      onClick={() => handleTriggerScan(target.id)}
                      className="flex-1 flex items-center justify-center gap-1.5 px-3 py-2 bg-cyber-green/10 border border-cyber-green/20 text-cyber-green font-mono text-xs font-bold uppercase rounded-sm hover:bg-cyber-green/20 transition-colors"
                    >
                      <Play className="w-3 h-3" />
                      Scan
                    </button>
                    <button
                      onClick={() => handleDeleteTarget(target.id)}
                      className="px-3 py-2 bg-cyber-pink/10 border border-cyber-pink/20 text-cyber-pink rounded-sm hover:bg-cyber-pink/20 transition-colors"
                    >
                      <Trash2 className="w-3.5 h-3.5" />
                    </button>
                  </div>

                  {/* Timestamp */}
                  <p className="text-[9px] font-mono text-cyber-muted mt-3 text-center">
                    Created {new Date(target.createdAt).toLocaleDateString()}
                  </p>
                </div>
              ))}
            </div>
          )}

        </main>
      </div>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { 
  Shield, Layers, Zap, Globe, Search, Plus,
  Sparkles, RefreshCcw, Wifi, Play, StopCircle,
  Trash2, Settings, Activity
} from 'lucide-react';
import Link from 'next/link';
import { apiClient } from '@/lib/api-client';
import { useRouter } from 'next/navigation';

export default function ListenersPage() {
  const router = useRouter();

  // Auth check
  useEffect(() => {
    const token = localStorage.getItem('vulnx_token');
    if (!token) {
      router.push('/login');
    }
  }, [router]);

  // State
  const [listeners, setListeners] = useState<any[]>([]);
  const [selectedListener, setSelectedListener] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [stats, setStats] = useState<any>(null);

  // Fetch listeners on mount
  useEffect(() => {
    fetchListeners();
    fetchStats();
  }, []);

  const fetchListeners = async () => {
    try {
      setLoading(true);
      setError('');
      const data = await apiClient.getListeners();
      setListeners(data);

      if (data.length > 0 && !selectedListener) {
        setSelectedListener(data[0]);
      }
    } catch (err: any) {
      console.error('Failed to fetch listeners:', err);
      setError(err.message || 'Failed to load listeners');
    } finally {
      setLoading(false);
    }
  };

  const fetchStats = async () => {
    try {
      const data = await apiClient.getListenerStats();
      setStats(data);
    } catch (err: any) {
      console.error('Failed to fetch stats:', err);
    }
  };

  // Create new listener
  const handleCreateListener = () => {
    const name = prompt('Enter listener name:');
    if (!name) return;

    const port = prompt('Enter port number:', '4444');
    if (!port) return;

    const type = prompt('Enter type (REVERSE_TCP/REVERSE_HTTPS/BIND_TCP/METERPRETER):', 'REVERSE_TCP');
    if (!type) return;

    createListener(name, parseInt(port), type);
  };

  const createListener = async (name: string, port: number, type: string) => {
    try {
      const newListener = await apiClient.createListener({
        name,
        type: type.toUpperCase() as any,
        port,
        host: '0.0.0.0',
        protocol: 'TCP',
        payload: 'windows/x64/meterpreter/reverse_tcp',
        encoding: 'Base64'
      });

      setListeners(prev => [newListener, ...prev]);
      setSelectedListener(newListener);
      alert(`Listener "${name}" created successfully!`);
      await fetchStats();
    } catch (err: any) {
      alert('Failed to create listener: ' + err.message);
    }
  };

  // Start listener
  const handleStartListener = async (listenerId: string) => {
    try {
      const updated = await apiClient.startListener(listenerId);
      setListeners(prev => prev.map(l => l.id === listenerId ? updated : l));
      if (selectedListener?.id === listenerId) {
        setSelectedListener(updated);
      }
      alert('Listener started successfully!');
      await fetchStats();
    } catch (err: any) {
      alert('Failed to start listener: ' + err.message);
    }
  };

  // Stop listener
  const handleStopListener = async (listenerId: string) => {
    try {
      const updated = await apiClient.stopListener(listenerId);
      setListeners(prev => prev.map(l => l.id === listenerId ? updated : l));
      if (selectedListener?.id === listenerId) {
        setSelectedListener(updated);
      }
      alert('Listener stopped successfully!');
      await fetchStats();
    } catch (err: any) {
      alert('Failed to stop listener: ' + err.message);
    }
  };

  // Delete listener
  const handleDeleteListener = async (listenerId: string) => {
    if (!confirm('Are you sure you want to delete this listener?')) return;

    try {
      await apiClient.deleteListener(listenerId);
      setListeners(prev => prev.filter(l => l.id !== listenerId));

      if (selectedListener?.id === listenerId) {
        setSelectedListener(listeners[0] || null);
      }

      alert('Listener deleted successfully!');
      await fetchStats();
    } catch (err: any) {
      alert('Failed to delete listener: ' + err.message);
    }
  };

  // Filter listeners
  const filteredListeners = listeners.filter(l => 
    l.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    l.port.toString().includes(searchQuery)
  );

  // Loading state
  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-[#050812]">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-cyber-green border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-cyber-green font-mono text-sm uppercase tracking-wider">
            Loading Listeners...
          </p>
        </div>
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-[#050812] p-6">
        <div className="bg-[#0b1120] border border-cyber-pink/20 rounded-sm p-6 max-w-md">
          <div className="flex items-center gap-3 mb-4">
            <div className="w-12 h-12 rounded-full bg-cyber-pink/10 flex items-center justify-center">
              <span className="text-2xl">⚠️</span>
            </div>
            <div>
              <h3 className="text-white font-heading font-bold text-lg">Error</h3>
              <p className="text-cyber-muted text-xs font-mono">Failed to load listeners</p>
            </div>
          </div>
          <p className="text-white font-mono text-sm mb-4">{error}</p>
          <button 
            onClick={fetchListeners}
            className="w-full bg-cyber-green text-black font-heading font-bold text-xs uppercase py-2 rounded-sm hover:bg-cyber-green/90 transition-colors"
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#050812] text-cyber-text font-sans overflow-hidden select-none scanline">

      {/* LEFT SIDEBAR */}
      <aside className="w-64 bg-[#080b14] border-r border-white/5 flex flex-col justify-between shrink-0 h-full overflow-y-auto">
        <div className="space-y-6 pt-6">
          <div className="px-6 flex items-center gap-3">
            <div className="p-2 bg-gradient-to-br from-cyber-green to-cyber-blue border border-black shadow-[2px_2px_0px_0px_rgba(0,0,0,1)] rounded-sm">
              <Shield className="w-5 h-5 text-black" />
            </div>
            <div>
              <span className="font-heading font-extrabold text-base tracking-tight text-white block">
                VULNX <span className="text-cyber-green">HUNTER</span>
              </span>
              <span className="text-[8px] font-mono text-cyber-blue tracking-widest block uppercase font-bold">
                Workspaces Center
              </span>
            </div>
          </div>

          <nav className="space-y-5 px-3">
            <div className="space-y-1">
              <Link 
                href="/dashboard"
                className="w-full flex items-center gap-2.5 px-3 py-2 rounded-sm text-xs font-heading font-bold uppercase text-cyber-muted hover:text-white hover:bg-white/[0.02] transition-colors"
              >
                <Layers className="w-4 h-4" />
                <span>Dashboard</span>
              </Link>
            </div>

            <div className="space-y-1">
              <span className="px-3 text-[9px] font-mono text-white/30 uppercase tracking-widest font-bold block mb-2">
                RECON & SCAN
              </span>
              {[
                { id: 'targets', label: 'Targets', icon: Globe, path: '/targets' },
                { id: 'listeners', label: 'Listeners', icon: Wifi, path: '/listeners' },
                { id: 'ai-assistant', label: 'AI Assistant', icon: Sparkles, path: '/ai-assistant' },
              ].map(item => {
                const Icon = item.icon;
                const isActive = item.id === 'listeners';
                return (
                  <Link
                    key={item.id}
                    href={item.path}
                    className={`w-full flex items-center gap-2.5 px-3 py-2 rounded-sm text-xs font-heading font-bold uppercase transition-all ${
                      isActive
                        ? 'bg-cyber-green/10 text-cyber-green border border-cyber-green/20'
                        : 'text-cyber-muted hover:text-white hover:bg-white/[0.02]'
                    }`}
                  >
                    <Icon className="w-4 h-4" />
                    <span>{item.label}</span>
                  </Link>
                );
              })}
            </div>
          </nav>
        </div>

        <div className="p-4 border-t border-white/5">
          <button
            onClick={() => {
              apiClient.logout();
              router.push('/login');
            }}
            className="w-full px-3 py-2 bg-cyber-pink/10 border border-cyber-pink/20 text-cyber-pink font-mono text-xs font-bold uppercase rounded-sm hover:bg-cyber-pink/20 transition-colors"
          >
            Logout
          </button>
        </div>
      </aside>

      {/* MAIN CONTENT */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">

        {/* Header */}
        <header className="h-16 border-b border-white/5 px-6 flex justify-between items-center bg-[#080b14]/50 backdrop-blur-md shrink-0">
          <div className="relative w-80">
            <Search className="absolute left-3 top-2.5 w-4 h-4 text-cyber-muted" />
            <input 
              type="text" 
              placeholder="Search listeners..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-[#050812] border border-white/10 focus:border-cyber-green outline-none py-1.5 pl-9 pr-4 text-xs font-mono text-white rounded-sm placeholder-cyber-muted/60 transition-all"
            />
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => { fetchListeners(); fetchStats(); }}
              className="p-2 border border-white/5 hover:border-cyber-green bg-[#080b14] text-cyber-muted hover:text-white rounded-sm transition-all"
              title="Refresh"
            >
              <RefreshCcw className="w-4.5 h-4.5" />
            </button>

            <button
              onClick={handleCreateListener}
              className="flex items-center gap-2 px-4 py-2 bg-cyber-green text-black font-heading font-bold text-xs uppercase rounded-sm hover:bg-cyber-green/90 transition-colors"
            >
              <Plus className="w-4 h-4" />
              New Listener
            </button>
          </div>
        </header>

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto p-6">

          {/* Title & Stats */}
          <div className="mb-6">
            <h1 className="font-heading font-bold text-2xl text-white tracking-tight mb-4">
              Listeners Management
            </h1>

            {/* Stats Cards */}
            {stats && (
              <div className="grid grid-cols-2 md:grid-cols-6 gap-4 mb-6">
                {[
                  { label: 'Total Listeners', val: stats.totalListeners, color: 'text-cyber-blue' },
                  { label: 'Active', val: stats.activeListeners, color: 'text-cyber-green' },
                  { label: 'Inactive', val: stats.inactiveListeners, color: 'text-cyber-muted' },
                  { label: 'Total Connections', val: stats.totalConnections, color: 'text-cyber-purple' },
                  { label: 'Active Connections', val: stats.activeConnections, color: 'text-cyber-green' },
                  { label: 'Error', val: stats.errorListeners || 0, color: 'text-cyber-pink' },
                ].map((stat, idx) => (
                  <div key={idx} className="bg-[#0b1120] border border-white/5 p-3 rounded-sm">
                    <p className="text-[8px] font-mono text-cyber-muted uppercase tracking-wider mb-1">{stat.label}</p>
                    <p className={`text-xl font-heading font-bold ${stat.color}`}>{stat.val}</p>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Listeners Grid */}
          {filteredListeners.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20">
              <Wifi className="w-16 h-16 text-cyber-muted mb-4" />
              <h3 className="text-white font-heading font-bold text-lg mb-2">No Listeners Found</h3>
              <p className="text-cyber-muted font-mono text-sm mb-4">
                {searchQuery ? 'No listeners match your search' : 'Create your first listener to get started'}
              </p>
              {!searchQuery && (
                <button
                  onClick={handleCreateListener}
                  className="flex items-center gap-2 px-4 py-2 bg-cyber-green text-black font-heading font-bold text-xs uppercase rounded-sm hover:bg-cyber-green/90 transition-colors"
                >
                  <Plus className="w-4 h-4" />
                  Create Listener
                </button>
              )}
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {filteredListeners.map((listener) => (
                <div 
                  key={listener.id}
                  className="bg-[#0b1120] border border-white/5 rounded-sm p-4 hover:border-cyber-green/20 transition-all"
                >
                  {/* Listener Header */}
                  <div className="flex justify-between items-start mb-3">
                    <div className="flex-1">
                      <h3 className="text-white font-heading font-bold text-sm mb-1">
                        {listener.name}
                      </h3>
                      <p className="text-cyber-muted font-mono text-xs">
                        {listener.host}:{listener.port}
                      </p>
                    </div>
                    <span className={`text-[8px] font-mono font-bold px-2 py-1 rounded-sm ${
                      listener.status === 'ACTIVE' 
                        ? 'bg-cyber-green/10 text-cyber-green border border-cyber-green/20 animate-pulse' 
                        : listener.status === 'ERROR'
                        ? 'bg-cyber-pink/10 text-cyber-pink border border-cyber-pink/20'
                        : 'bg-cyber-muted/10 text-cyber-muted border border-cyber-muted/20'
                    }`}>
                      {listener.status}
                    </span>
                  </div>

                  {/* Details */}
                  <div className="space-y-2 mb-3 text-xs font-mono">
                    <div className="flex justify-between">
                      <span className="text-cyber-muted">Type:</span>
                      <span className="text-white font-bold">{listener.type}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-cyber-muted">Protocol:</span>
                      <span className="text-white">{listener.protocol}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-cyber-muted">Connections:</span>
                      <span className="text-cyber-green font-bold">{listener._count?.connections || 0}</span>
                    </div>
                  </div>

                  {/* Actions */}
                  <div className="flex gap-2">
                    {listener.status === 'ACTIVE' ? (
                      <button
                        onClick={() => handleStopListener(listener.id)}
                        className="flex-1 flex items-center justify-center gap-1.5 px-3 py-2 bg-cyber-pink/10 border border-cyber-pink/20 text-cyber-pink font-mono text-xs font-bold uppercase rounded-sm hover:bg-cyber-pink/20 transition-colors"
                      >
                        <StopCircle className="w-3 h-3" />
                        Stop
                      </button>
                    ) : (
                      <button
                        onClick={() => handleStartListener(listener.id)}
                        className="flex-1 flex items-center justify-center gap-1.5 px-3 py-2 bg-cyber-green/10 border border-cyber-green/20 text-cyber-green font-mono text-xs font-bold uppercase rounded-sm hover:bg-cyber-green/20 transition-colors"
                      >
                        <Play className="w-3 h-3" />
                        Start
                      </button>
                    )}
                    <button
                      onClick={() => handleDeleteListener(listener.id)}
                      className="px-3 py-2 bg-cyber-pink/10 border border-cyber-pink/20 text-cyber-pink rounded-sm hover:bg-cyber-pink/20 transition-colors"
                    >
                      <Trash2 className="w-3.5 h-3.5" />
                    </button>
                  </div>

                  {/* Timestamp */}
                  <p className="text-[9px] font-mono text-cyber-muted mt-3 text-center">
                    Created {new Date(listener.createdAt).toLocaleDateString()}
                  </p>
                </div>
              ))}
            </div>
          )}

        </main>
      </div>
    </div>
  );
}
